package genxsolution.vms.vmsbackend.maintenance_management.maintenance_program_template.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_program_template.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_program_template.mapper.MaintenanceProgramTemplateMapper; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_program_template.repository.MaintenanceProgramTemplateRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class MaintenanceProgramTemplateService { private final MaintenanceProgramTemplateRepository repository; private final MaintenanceProgramTemplateMapper mapper; public MaintenanceProgramTemplateService(MaintenanceProgramTemplateRepository repository,MaintenanceProgramTemplateMapper mapper){this.repository=repository;this.mapper=mapper;} public List<MaintenanceProgramTemplateResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public MaintenanceProgramTemplateResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenanceProgramTemplate", String.valueOf(id))); } public MaintenanceProgramTemplateResponse create(MaintenanceProgramTemplateUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public MaintenanceProgramTemplateResponse update(UUID id,MaintenanceProgramTemplateUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenanceProgramTemplate", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("MaintenanceProgramTemplate", String.valueOf(id)); } }
